import java.io.*;
import org.owasp.encoder.Encode;

public class XSSSecureCode {

    public static void main(String[] args) throws IOException {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));

        System.out.println("Enter your name:");
        String userName = reader.readLine();

        // Sanitize and encode user input before displaying it
        String safeUserName = Encode.forHtml(userName);

        System.out.println("Hello, " + safeUserName + "! Welcome to our website.");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
